if (Exoplanets.getFlagShowExoplanets()) {
    core.debug("Exoplanet systems are visible");
} else {
    Exoplanets.setFlagShowExoplanets(true);
}

// Show exoplanet systems
Exoplanets.setFlagShowExoplanets(true);

// Hide exoplanet systems
Exoplanets.setFlagShowExoplanets(false);

// Read using property
var visible = core.getStelProperty('Exoplanets.showExoplanets');

// Write using property
core.setStelProperty('Exoplanets.showExoplanets', true);

if (Exoplanets.getFlagShowExoplanetsDesignations()) {
    core.debug("Exoplanet designations are visible");
}

// Show exoplanet system designations
Exoplanets.setFlagShowExoplanetsDesignations(true);

// Hide designations
Exoplanets.setFlagShowExoplanetsDesignations(false);

if (Exoplanets.getFlagShowExoplanetsNumbers()) {
    core.debug("Exoplanet counts are shown");
}

// Show how many exoplanets each system has
Exoplanets.setFlagShowExoplanetsNumbers(true);

// Hide planet counts
Exoplanets.setFlagShowExoplanetsNumbers(false);

if (Exoplanets.getDisplayMode()) {
    core.debug("Exoplanet distribution mode is enabled");
}

// Show exoplanet distribution density
Exoplanets.setDisplayMode(true);

// Show individual system markers
Exoplanets.setDisplayMode(false);

if (Exoplanets.getTimelineMode()) {
    core.debug("Only exoplanets discovered by current date are shown");
}

// Show only exoplanets discovered by current date
Exoplanets.setTimelineMode(true);

// Show all known exoplanets
Exoplanets.setTimelineMode(false);

// Set date to 1995 to see first exoplanets
core.setDate("1995-12-01T00:00:00");
Exoplanets.setTimelineMode(true);

if (Exoplanets.getHabitableMode()) {
    core.debug("Only systems with potentially habitable planets are shown");
}

// Show only potentially habitable exoplanets
Exoplanets.setHabitableMode(true);

// Show all exoplanets
Exoplanets.setHabitableMode(false);

// Set exoplanet markers to cyan
var cyan = core.vec3f(0.2, 0.8, 0.9);
Exoplanets.setMarkerColor(cyan);

// Set to yellow-orange
var orange = core.vec3f(1.0, 0.7, 0.2);
Exoplanets.setMarkerColor(orange);

// Read color using property
var colorStr = core.getStelProperty('Exoplanets.markerColor');
var parts = colorStr.split(',');
var r = parseFloat(parts[0]);
var g = parseFloat(parts[1]);
var b = parseFloat(parts[2]);

// Write using method
var newColor = core.vec3f(0.2, 0.8, 0.9);
Exoplanets.setMarkerColor(newColor);

// Set habitable exoplanets to bright green
var brightGreen = core.vec3f(0.2, 0.9, 0.2);
Exoplanets.setHabitableColor(brightGreen);

// Set to gold
var gold = core.vec3f(1.0, 0.8, 0.2);
Exoplanets.setHabitableColor(gold);

if (Exoplanets.getUpdatesEnabled()) {
    core.debug("Automatic exoplanet catalog updates are enabled");
}

// Enable automatic catalog updates
Exoplanets.setUpdatesEnabled(true);

// Disable automatic updates
Exoplanets.setUpdatesEnabled(false);

// Manually update exoplanet catalog
Exoplanets.updateJSON();
core.debug("Exoplanet catalog update started...");

// Wait for update to complete
core.wait(30);
core.debug("Exoplanet catalog updated");

// Update daily
Exoplanets.setUpdateFrequencyHours(24);

// Update weekly
Exoplanets.setUpdateFrequencyHours(168);

var state = Exoplanets.getUpdateState();
if (state === 0) core.debug("Updating catalog...");
else if (state === 1) core.debug("No updates needed");
else if (state === 2) core.debug("Catalog updated successfully");
else if (state === 3) core.debug("Download error occurred");

if (Exoplanets.getEnableAtStartup()) {
    core.debug("Exoplanets will load on next startup");
}

// Enable Exoplanets on next startup
Exoplanets.setEnableAtStartup(true);

// Disable Exoplanets on next startup
Exoplanets.setEnableAtStartup(false);

if (Exoplanets.getFlagShowExoplanetsButton()) {
    core.debug("Exoplanets toolbar button is visible");
}

// Show Exoplanets button on toolbar
Exoplanets.setFlagShowExoplanetsButton(true);

// Hide Exoplanets button
Exoplanets.setFlagShowExoplanetsButton(false);

// Reset all Exoplanets plugin settings to defaults
Exoplanets.restoreDefaults();
core.debug("Exoplanets settings restored to defaults");

// Get TRAPPIST-1 system (7 exoplanets, 3 in habitable zone)
var trappist = Exoplanets.getByID("TRAPPIST-1");
if (trappist) {
    core.debug("Found: " + trappist.getEnglishName());
    core.debug("Exoplanets in system: " + trappist.getCountExoplanets());
    core.debug("Potentially habitable: " + trappist.getCountHabitableExoplanets());
    core.moveToObject(trappist.getEnglishName(), 3);
} else {
    core.debug("System not found in catalog");
}

var allSystems = Exoplanets.getAllExoplanetarySystems();
core.debug("Total planetary systems: " + allSystems.length);

// Print first 10 system names
for (var i = 0; i < Math.min(10, allSystems.length); i++) {
    core.debug(allSystems[i].getEnglishName());
}

var system = Exoplanets.searchByID("TRAPPIST-1");
if (system) {
    core.debug("Moving to TRAPPIST-1 system");
    core.moveToObject(system.getEnglishName(), 3);
}

var system = Exoplanets.searchByName("TRAPPIST-1");
if (system) {
    core.debug("Found TRAPPIST-1 system");
    core.debug("Distance: " + system.getDistance() + " pc");
    core.moveToObject(system.getEnglishName(), 3);
}

// Use Celsius for exoplanet temperatures
Exoplanets.setCurrentTemperatureScale(1);

// Use Fahrenheit
Exoplanets.setCurrentTemperatureScale(2);

// Use Kelvin (scientific)
Exoplanets.setCurrentTemperatureScale(0);

var scale = Exoplanets.getCurrentTemperatureScale();
var scaleName = scale === 0 ? "Kelvin" : (scale === 1 ? "Celsius" : "Fahrenheit");
core.debug("Temperature scale: " + scaleName);
